mapper.select:
SELECT gu.id, gu.user_no AS userNo, gu.user_name AS userName, gu.user_type AS userType, gu.area_code AS areaCode, gu.area_name AS areaName, CONCAT( IFNULL(l1.area_name, ''), IF(l1.area_name IS NOT NULL AND l2.area_name IS NOT NULL, '/', ''), IFNULL(l2.area_name, ''), IF(l2.area_name IS NOT NULL AND l3.area_name IS NOT NULL, '/', ''), IFNULL(l3.area_name, '') ) AS areaNameDisplay, gu.address, gu.building_info AS buildingInfo, gu.contact_phone AS contactPhone, gu.id_card AS idCard, gu.status, gu.create_time AS createTime FROM gas_user gu LEFT JOIN tbl_area_node l3 ON CASE WHEN gu.area_code LIKE '%/%/%' THEN SUBSTRING_INDEX(gu.area_code, '/', -1) ELSE NULL END = l3.code LEFT JOIN tbl_area_node l2 ON CASE WHEN gu.area_code LIKE '%/%/%' THEN SUBSTRING_INDEX(SUBSTRING_INDEX(gu.area_code, '/', 2), '/', -1) WHEN gu.area_code LIKE '%/%' THEN SUBSTRING_INDEX(gu.area_code, '/', -1) ELSE NULL END = l2.code LEFT JOIN tbl_area_node l1 ON CASE WHEN gu.area_code LIKE '%/%' THEN SUBSTRING_INDEX(gu.area_code, '/', 1) ELSE NULL END = l1.code WHERE gu.deleted = 0
AND gu.user_no LIKE CONCAT('%', #{userNo}, '%')
AND gu.user_name LIKE CONCAT('%', #{userName}, '%')
AND gu.address LIKE CONCAT('%', #{address}, '%')
AND gu.user_type = #{userType}
ORDER BY gu.create_time DESC LIMIT #{start}, #{length}

mapper.update:
UPDATE gas_user
SET deleted = 1
WHERE id = #{id}

mapper.select:
SELECT COUNT(*)
FROM gas_user
WHERE user_no = #{userNo}

    AND id != #{id}
